			line-height: 1.4;
		}
	}

	.sidebar-entry__divider {
		color: var(--text-3);

		&:last-child {
			display: none;
		}
	}

	.sidebar-entry__branch {
		display: flex;
		align-items: center;
		gap: 4px;
		color: var(--text-2);
	}
</style>
